('3eme-spt-6-s2-l2', 'Dilution d''une solution acide ou basique', 'Variation du pH par dilution et échelle de pH.', '3eme-spt-6', '3eme-spt-6-s2', 5),
('3eme-spt-6-s2-l3', 'Réaction entre acide chlorhydrique et soude', 'Étude expérimentale de la neutralisation avec un indicateur coloré et équation-bilan.', '3eme-spt-6', '3eme-spt-6-s2', 6),
('3eme-spt-7-s1-l1', 'Présentation d''un détecteur et la chaîne électronique', 'Observer la chaîne électronique : circuit de commande et circuit commandé.', '3eme-spt-7', '3eme-spt-7-s1', 1),
