('3eme-spt-7-s1-l4', 'Les dipôles commandés', 'Identifier un dipôle commandé : sonnette, buzzer, lampe ou DEL.', '3eme-spt-7', '3eme-spt-7-s1', 4),
('3eme-spt-7-s1-l5', 'Réalisation et test d''un détecteur', 'Fabriquer un détecteur avec un capteur choisi puis tester son fonctionnement.', '3eme-spt-7', '3eme-spt-7-s1', 5),
