('3eme-spt-10-s1-l2', 'Les dangers du courant électrique', 'Le corps humain conducteur, électrocution et causes possibles.', '3eme-spt-10', '3eme-spt-10-s1', 2),
('3eme-spt-10-s1-l3', 'Protection au niveau des prises', 'Cache-prise et interrupteur associé à chaque prise électrique.', '3eme-spt-10', '3eme-spt-10-s1', 3),
('3eme-spt-10-s1-l4', 'Protection par le disjoncteur différentiel', 'Principe et symbole du disjoncteur différentiel.', '3eme-spt-10', '3eme-spt-10-s1', 4),
