('3eme-spt-12-s1-l1', 'Formes d''énergie dans des objets techniques', 'Formes d''énergie et transformations dans la lampe, la bicyclette, la voiture, une centrale.', '3eme-spt-12', '3eme-spt-12-s1', 1),
('3eme-spt-12-s1-l2', 'Importance de l''énergie électrique', 'Justifier l''importance de l''énergie électrique dans les objets techniques.', '3eme-spt-12', '3eme-spt-12-s1', 2),
